export function removeParametersFromUrl(url: string) {
  return url.split('?')[0];
}

export function urlWithTrailingSlash(url: string) {
  return url.substr(-1) === '/' ? url : url + '/';
}

export function getRedirectUri(url: string) {
  const redirect_uri = new URLSearchParams(url).get('redirect_uri') || '';
  return redirect_uri.replace(/%3A/g, ':').replace(/%2F/g, '/');
}
